parameters.functionCode:
// Flatten variants, filter inventory_quantity < 5
const threshold = 5;
const low = [];
for (const p of ($input.first().json.products || [])) {
  for (const v of (p.variants || [])) {
    if ((v.inventory_quantity ?? 0) < threshold) {
      low.push({ product: p.title, variant: v.title, qty: v.inventory_quantity });
    }
  }
}
if (low.length === 0) return [];
return [{ json: { low, count: low.length } }];

